svg.script:

document.getElementById('btn').addEventListener('click', () => {
  // We use .postMessage but wrap it to ensure the 'port' stays open
  try {
    window.parent.postMessage({ 
      action: 'load_game', 
      url: 'https://martiantech.github.io/drive-mad/' 
    }, '*');
  } catch(e) {
    console.error("Failed to send message:", e);
  }
});
